---播放黑幕遮罩

---@class LBattleSkillActFadeExtra
local LBattleSkillActFadeExtra = classX("LBattleSkillActFadeExtra", nil)

local LBattleSkillActFadeTop = require("LApp.gameplay.videobattle.view.skillact.LBattleSkillActFadeTop")

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActFadeExtra.Execute(player,effData, playState)
    LBattleSkillActFadeTop.ExecuteTopMask(player, effData,nil,function ()
        player:ChangeHitHeroLayer(2)
        local target = player:GetTargetAtkUnitView()
        if target then
            target:ResetRender()
        end
    end)

    player:ChangeHitHeroLayer(1)

    local target = player:GetTargetAtkUnitView()
    if target then
        target:ToUpperLayer()
    end
end

return LBattleSkillActFadeExtra